#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#include <stdbool.h>
#define N 1001
#define INF 1000000000000000000LL
long long d[N];
int adj[N][N];
bool vis[N];
void dijkstra(int source, int n) {
    for (int i = 1; i <= n; i++) {
        d[i] = INF;
        vis[i] = false;
    }
    d[source] = 0;
    for (int i = 1; i <= n; i++) {
        int v = -1;
        long long cur = INF;
        for (int j = 1; j <= n; j++) {
            if (cur >= d[j] && !vis[j]) {
                v = j;
                cur = d[j];
            }
        }
        vis[v] = true;
        for (int u = 1; u <= n; u++) {
            if (adj[v][u] != 0 && d[u] > d[v] + adj[v][u]) {
                d[u] = d[v] + adj[v][u];
            }
        }
    }
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= n; j++) {
                adj[i][j] = 0;
            }
        }
        for (int i = 0; i < m; i++) {
            int a, b, w;
            scanf("%d %d %d", &a, &b, &w);
            adj[a][b] = w;
            adj[b][a] = w;
        }
        dijkstra(1, n);
        for (int i = 1; i <= n; i++) {
            if (d[i] == INF) printf("-1 ");
            else printf("%lld ", d[i]);
        }
        printf("\n");
    }
    return 0;
}

